// Extract domain from URL for Hunter.io lookup
const url = $input.first().json.website_url;
const domain = new URL(url).hostname.replace('www.', '');

return [{
  json: {
    lead_id: $input.first().json.lead_id,
    retailer_name: $input.first().json.retailer_name,
    website_url: url,
    domain: domain
  }
}];

// Filter Hunter.io results for buyer/owner/purchasing titles
const hunterData = $('Hunter.io Domain Search').first().json;
const inputData = $('Extract Domain').first().json;

const targetTitles = [
  'buyer', 'purchasing', 'merchandis', 'procurement',
  'owner', 'founder', 'ceo', 'president', 'director',
  'manager', 'vp', 'vice president', 'head of'
];

const emails = (hunterData.data?.emails || []);

const relevantContacts = emails
  .filter(email => {
    if (!email.position) return false;
    const pos = email.position.toLowerCase();
    return targetTitles.some(title => pos.includes(title));
  })
  .map(email => ({
    contact_name: [email.first_name, email.last_name].filter(Boolean).join(' ') || 'Unknown',
    email: email.value,
    company: inputData.retailer_name,
    title: email.position,
    confidence: email.confidence,
    source: 'Hunter.io',
    lead_id: inputData.lead_id
  }));

// Fallback: top 3 by confidence if no title match
const fallbackContacts = emails
  .sort((a, b) => b.confidence - a.confidence)
  .slice(0, 3)
  .map(email => ({
    contact_name: [email.first_name, email.last_name].filter(Boolean).join(' ') || 'Unknown',
    email: email.value,
    company: inputData.retailer_name,
    title: email.position || 'Unknown',
    confidence: email.confidence,
    source: 'Hunter.io',
    lead_id: inputData.lead_id
  }));

const contacts = relevantContacts.length > 0 ? relevantContacts : fallbackContacts;

return [{
  json: {
    lead_id: inputData.lead_id,
    retailer_name: inputData.retailer_name,
    domain: inputData.domain,
    contacts: contacts,
    total_emails_found: emails.length
  }
}];

